/* Evidence: cmem-c23-initialization-tools-3ivh3u */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 4859; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


struct initialized_record { unsigned initialized; int value; };

static int evidence_cmem_c23_initialization_tools_3ivh3u(const struct initialized_record *record, int fallback) {
  if (record == NULL || !record->initialized) return fallback;
  return record->value;
}

int main(void) {
  struct initialized_record record = { 0u, 0 };
  int before = evidence_cmem_c23_initialization_tools_3ivh3u(&record, -1);
  record.value = 14;
  record.initialized = 1u;
  int after = evidence_cmem_c23_initialization_tools_3ivh3u(&record, -1);
  int invariant = before == -1 && after == 14;
  printf("initialization value=%d invariant=%d\n", after, invariant);
  return invariant ? 0 : 1;
}
